mapper.select:
SELECT p.*, c.name as category_name
FROM products p
LEFT JOIN categories c ON p.category_id = c.id
WHERE 1=1

    AND p.name LIKE CONCAT('%', #{search}, '%')


    AND p.status = #{status}


    AND p.category_id = #{categoryId}


    ORDER BY 


            c.name


            p.${sortField}



        ${sortOrder}



    ORDER BY p.id DESC

mapper.update:
UPDATE products
SET category_id = #{toCategoryId}
WHERE category_id = #{fromCategoryId}
